import { useEffect } from "react";
import { useTranslation } from "react-i18next";
import { useSiteSettings } from "@/hooks/useSiteSettings";

/**
 * Dynamic SEO component that updates document title and meta description
 * based on site settings from the database.
 */
const DynamicSEO = () => {
  const { i18n } = useTranslation();
  const { settings } = useSiteSettings();

  useEffect(() => {
    // Only update if we have actual settings from the database
    // Don't update with fallbacks to avoid flashing default text
    if (!settings) return;

    // Get the title based on current language - only if setting exists
    const getTitle = () => {
      switch (i18n.language) {
        case "zh":
          return settings.site_title_zh;
        case "pt":
          return settings.site_title_pt;
        default:
          return settings.site_title_en;
      }
    };

    // Get the description based on current language - only if setting exists
    const getDescription = () => {
      switch (i18n.language) {
        case "zh":
          return settings.site_description_zh;
        case "pt":
          return settings.site_description_pt;
        default:
          return settings.site_description_en;
      }
    };

    const title = getTitle();
    const description = getDescription();

    // Only update if we have actual values from database
    if (title) {
      document.title = title;
      
      const ogTitle = document.querySelector('meta[property="og:title"]');
      if (ogTitle) {
        ogTitle.setAttribute("content", title);
      }
    }

    if (description) {
      const metaDescription = document.querySelector('meta[name="description"]');
      if (metaDescription) {
        metaDescription.setAttribute("content", description);
      }

      const ogDescription = document.querySelector('meta[property="og:description"]');
      if (ogDescription) {
        ogDescription.setAttribute("content", description);
      }
    }
  }, [settings, i18n.language]);

  return null;
};

export default DynamicSEO;
