import { useCallback, useRef } from 'react';

// Map of route paths to their lazy component loaders
const routeLoaders: Record<string, () => Promise<unknown>> = {
  '/': () => import('@/pages/Home'),
  '/restaurants': () => import('@/pages/Restaurants'),
  '/activities': () => import('@/pages/Activities'),
  '/community': () => import('@/pages/Community'),
  '/map': () => import('@/pages/Map'),
  '/join-us': () => import('@/pages/JoinUs'),
  '/auth': () => import('@/pages/Auth'),
  '/profile': () => import('@/pages/Profile'),
  '/dashboard': () => import('@/pages/Dashboard'),
};

// Resolve a path (which may include sub-routes like /restaurants/landmark)
// to the closest registered route loader key.
const resolveLoaderKey = (path: string): string | null => {
  if (routeLoaders[path]) return path;
  // Try parent paths: /restaurants/landmark -> /restaurants
  const segments = path.split('/').filter(Boolean);
  while (segments.length > 0) {
    segments.pop();
    const candidate = '/' + segments.join('/');
    if (routeLoaders[candidate]) return candidate;
  }
  return null;
};

// Track which routes have already been prefetched
const prefetchedRoutes = new Set<string>();

export const usePrefetch = () => {
  const timeoutRef = useRef<NodeJS.Timeout | null>(null);

  const prefetch = useCallback((path: string) => {
    // Normalize path - remove query strings and hash
    const normalizedPath = path.split('?')[0].split('#')[0];
    const loaderKey = resolveLoaderKey(normalizedPath);

    // Don't prefetch if already loaded or if no loader exists
    if (!loaderKey || prefetchedRoutes.has(loaderKey)) {
      return;
    }

    // Mark as prefetched immediately to prevent duplicate requests
    prefetchedRoutes.add(loaderKey);

    // Load the module
    routeLoaders[loaderKey]().catch(() => {
      // If loading fails, remove from prefetched so it can be retried
      prefetchedRoutes.delete(loaderKey);
    });
  }, []);

  const prefetchOnHover = useCallback((path: string, delay = 100) => {
    // Clear any pending prefetch
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
    }

    // Delay prefetch slightly to avoid prefetching on quick mouse passes
    timeoutRef.current = setTimeout(() => {
      prefetch(path);
    }, delay);
  }, [prefetch]);

  const cancelPrefetch = useCallback(() => {
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
      timeoutRef.current = null;
    }
  }, []);

  return { prefetch, prefetchOnHover, cancelPrefetch };
};

// Utility function for prefetching without hook
export const prefetchRoute = (path: string) => {
  const normalizedPath = path.split('?')[0].split('#')[0];
  const loaderKey = resolveLoaderKey(normalizedPath);

  if (!loaderKey || prefetchedRoutes.has(loaderKey)) {
    return;
  }

  prefetchedRoutes.add(loaderKey);
  routeLoaders[loaderKey]().catch(() => {
    prefetchedRoutes.delete(loaderKey);
  });
};
