import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export type UserRole = "user" | "merchant" | "supervisor" | "admin" | "staff";

export const useUserRole = () => {
  const { user } = useAuth();

  const { data: role, isLoading } = useQuery({
    queryKey: ["user-roles", user?.id],
    queryFn: async () => {
      if (!user) return "user" as UserRole;
      
      const { data, error } = await supabase
        .from("user_roles")
        .select("role")
        .eq("user_id", user.id)
        .maybeSingle();

      if (error) {
        if (error.code === "406" || error.message?.includes("Not Acceptable")) {
          console.warn("[useUserRole] Got 406, returning default role. Will retry on next interval.");
          return "user" as UserRole;
        }
        throw error;
      }
      return (data?.role as UserRole) || "user";
    },
    enabled: !!user,
    retry: (failureCount, error: any) => {
      if (error?.code === "406" || error?.message?.includes("Not Acceptable")) {
        return failureCount < 1;
      }
      return failureCount < 3;
    },
    retryDelay: (attemptIndex) => Math.min(1000 * 2 ** attemptIndex, 10000),
  });

  const { data: merchantType } = useQuery({
    queryKey: ["merchant-type", user?.id],
    queryFn: async () => {
      if (!user) return null;
      const { data } = await supabase
        .from("profiles")
        .select("merchant_type")
        .eq("id", user.id)
        .maybeSingle();
      return data?.merchant_type || null;
    },
    enabled: !!user && role === "merchant",
  });

  const hasRole = (checkRole: UserRole) => {
    return role === checkRole;
  };

  const isAdmin = role === "admin";
  const isSupervisor = role === "supervisor";
  const isMerchant = role === "merchant";
  const isStaff = role === "staff";
  const isShallowMerchant = isMerchant && merchantType === "shallow";

  const canAccessMerchantDashboard = isMerchant || isSupervisor || isAdmin;
  // Roles that may publish recipes & posts that require restaurant linkage
  const canCreateRecipe = isAdmin || isMerchant || isSupervisor || isStaff;
  // Roles that need a restaurant attached when posting (everyone except admin)
  const requiresRestaurantOnPost = isMerchant || isSupervisor || isStaff;

  return {
    role: role ?? "user",
    hasRole,
    isAdmin,
    isSupervisor,
    isMerchant,
    isStaff,
    isShallowMerchant,
    merchantType,
    isLoading,
    canAccessMerchantDashboard,
    canCreateRecipe,
    requiresRestaurantOnPost,
  };
};
