import { useCallback } from "react";
import { useNavigate } from "react-router-dom";

/**
 * Internal navigation depth tracker.
 * Increments on each internal navigation, so we know if navigate(-1) is safe.
 * Reset when the user enters from an external source (depth stays 0).
 */
let internalNavDepth = 0;

/**
 * Call this on every internal route change to track navigation depth.
 * Should be called once in a top-level component (e.g., App).
 */
export const incrementNavDepth = () => {
  internalNavDepth++;
};

/**
 * Reset depth (e.g., on initial load).
 */
export const resetNavDepth = () => {
  internalNavDepth = 0;
};

/**
 * Get current internal navigation depth.
 */
export const getNavDepth = () => internalNavDepth;

/**
 * Smart back navigation hook.
 * If there's internal navigation history, goes back with navigate(-1).
 * Otherwise, navigates to the provided default fallback route.
 *
 * @param defaultPath - Fallback route when no internal history exists (default: "/")
 * @returns goBack function
 *
 * @example
 * const goBack = useSmartBack("/community");
 * <button onClick={goBack}>Back</button>
 */
export const useSmartBack = (defaultPath: string = "/") => {
  const navigate = useNavigate();

  const goBack = useCallback(() => {
    if (internalNavDepth > 0) {
      navigate(-1);
    } else {
      navigate(defaultPath, { replace: true });
    }
  }, [navigate, defaultPath]);

  return goBack;
};
