/**
 * Clears all restaurant-related sessionStorage filters.
 * Called when navigating to /restaurants/* from the navigation bar
 * to ensure a fresh state (re-fetch location, no stale filters).
 */
export function clearRestaurantFilters() {
  const keys = [
    'restaurants-filter-search',
    'restaurants-filter-template',
    'restaurants-filter-types',
    'restaurants-filter-country',
    'restaurants-filter-district',
    'restaurants-filter-verified',
    'restaurants-filter-page',
    'restaurants-scroll-pos',
    'restaurants-nav-from-detail',
  ];
  keys.forEach((k) => sessionStorage.removeItem(k));
  // Increment a reset counter so the Restaurants page can detect nav-bar clicks
  // even when already on the same route (forces re-init)
  const count = parseInt(sessionStorage.getItem('restaurants-reset-counter') || '0', 10);
  sessionStorage.setItem('restaurants-reset-counter', String(count + 1));
}

