import { Link, LinkProps } from "react-router-dom";
import { forwardRef, useCallback } from "react";
import { usePrefetch } from "@/hooks/usePrefetch";

interface PrefetchLinkProps extends LinkProps {
  prefetchDelay?: number;
}

const PrefetchLink = forwardRef<HTMLAnchorElement, PrefetchLinkProps>(
  ({ to, prefetchDelay = 100, onMouseEnter, onMouseLeave, onTouchStart, onPointerDown, ...props }, ref) => {
    const { prefetch, prefetchOnHover, cancelPrefetch } = usePrefetch();
    
    const path = typeof to === 'string' ? to : to.pathname || '';

    const handleMouseEnter = useCallback(
      (e: React.MouseEvent<HTMLAnchorElement>) => {
        prefetchOnHover(path, prefetchDelay);
        onMouseEnter?.(e);
      },
      [path, prefetchDelay, prefetchOnHover, onMouseEnter]
    );

    const handleMouseLeave = useCallback(
      (e: React.MouseEvent<HTMLAnchorElement>) => {
        cancelPrefetch();
        onMouseLeave?.(e);
      },
      [cancelPrefetch, onMouseLeave]
    );

    // Mobile: kick off prefetch immediately on touch/pointer down so the
    // chunk starts downloading during the tap delay before navigation.
    const handleTouchStart = useCallback(
      (e: React.TouchEvent<HTMLAnchorElement>) => {
        prefetch(path);
        onTouchStart?.(e);
      },
      [path, prefetch, onTouchStart]
    );

    const handlePointerDown = useCallback(
      (e: React.PointerEvent<HTMLAnchorElement>) => {
        prefetch(path);
        onPointerDown?.(e);
      },
      [path, prefetch, onPointerDown]
    );

    return (
      <Link
        ref={ref}
        to={to}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
        onTouchStart={handleTouchStart}
        onPointerDown={handlePointerDown}
        {...props}
      />
    );
  }
);

PrefetchLink.displayName = "PrefetchLink";

export { PrefetchLink };
