import { Link, useLocation } from "react-router-dom";
import { PrefetchLink } from "@/components/PrefetchLink";
import { clearRestaurantFilters } from "@/lib/clearRestaurantFilters";
import { Button } from "@/components/ui/button";
import * as LucideIcons from "lucide-react";
import { User, Menu, LogOut, Shield, Ticket } from "lucide-react";

import { useState, useEffect, useMemo, useCallback, useRef } from "react";
import { Sheet, SheetContent, SheetTrigger, SheetTitle } from "@/components/ui/sheet";
import { VisuallyHidden } from "@radix-ui/react-visually-hidden";
import { useAuth } from "@/contexts/AuthContext";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { LanguageSwitcher } from "@/components/LanguageSwitcher";
import { useTranslation } from "react-i18next";
import { useUserRole } from "@/hooks/useUserRole";
import { useProfile } from "@/hooks/useProfile";
import { useSiteSettings } from "@/hooks/useSiteSettings";
import { useNavigationSettings, getDeviceSettings } from "@/hooks/useNavigationSettings";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuLabel, DropdownMenuSeparator, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import NotificationsDropdown from "@/components/NotificationsDropdown";
import { useIsMobile } from "@/hooks/use-mobile";
import { useEnvironment } from "@/hooks/useEnvironment";

const Navigation = () => {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const location = useLocation();
  const {
    user,
    signOut
  } = useAuth();
  const {
    t,
    i18n
  } = useTranslation();
  const {
    isAdmin,
    isSupervisor,
    isMerchant,
    canAccessMerchantDashboard
  } = useUserRole();
  const {
    data: profile
  } = useProfile();
  const {
    settings: siteSettings
  } = useSiteSettings();
  const { settings: navSettings, buttons, isLoading: isLoadingNav } = useNavigationSettings();
  const isMobile = useIsMobile();
  const { isWebView } = useEnvironment();

  // Scroll-aware nav: transparent + white text on home hero, white bg + dark text elsewhere
  const isHomePage = location.pathname === "/";
  const [scrolledPastHero, setScrolledPastHero] = useState(false);

  useEffect(() => {
    if (!isHomePage) {
      setScrolledPastHero(true);
      return;
    }
    setScrolledPastHero(false);
    const handleScroll = () => {
      // Hero is roughly the viewport height; switch at ~80% of viewport
      const threshold = window.innerHeight * 0.6;
      setScrolledPastHero(window.scrollY > threshold);
    };
    handleScroll();
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, [isHomePage]);

  // Derived: should nav use dark text (scrolled past hero or not on home)
  // On mobile, homepage always uses solid white nav (no transparent hero effect)
  const useDarkText = isMobile ? true : scrolledPastHero;
  
  const logoUrl = siteSettings?.logo_url;
  const logoWidth = siteSettings?.logo_width || 35;
  const logoHeight = siteSettings?.logo_height || 35;

  // Load user's language preference from database only on initial profile load
  const hasAppliedProfileLang = useRef(false);
  useEffect(() => {
    if (profile?.language_preference && !hasAppliedProfileLang.current) {
      hasAppliedProfileLang.current = true;
      const savedLang = localStorage.getItem("i18nextLng");
      // Only apply profile preference if no localStorage override exists
      if (!savedLang || savedLang === profile.language_preference) {
        if (profile.language_preference !== i18n.language) {
          i18n.changeLanguage(profile.language_preference);
        }
      }
    }
  }, [profile, i18n]);

  const getIconComponent = (iconName: string) => {
    const Icon = (LucideIcons as any)[iconName];
    return Icon || LucideIcons.Circle;
  };

  const getLocalizedLabel = (button: any) => {
    const lang = i18n.language;
    if (lang === "zh") return button.label_zh || button.label_en;
    if (lang === "pt") return button.label_pt || button.label_en;
    // For other languages, try to find a translation key based on the link
    const linkToKeyMap: Record<string, string> = {
      "/": "nav.map",
      "/map": "nav.mapView",
      "/restaurants": "nav.restaurants",
      "/restaurants/landmark": "nav.attractions",
      "/activities": "nav.activities",
      "/community": "nav.community",
      "/profile": "nav.profile",
      "/about-us": "nav.aboutUs",
      "/join-us": "nav.joinUs",
    };
    const key = linkToKeyMap[button.link];
    if (key) {
      const translated = t(key);
      if (translated !== key) return translated;
    }
    return button.label_en;
  };

  type NavItem = {
    to: string;
    icon: React.ComponentType<{ className?: string }>;
    label: string;
    showOnDesktop?: boolean;
    showOnTablet?: boolean;
    showOnMobile?: boolean;
  };

  const navItems: NavItem[] = useMemo(() => {
    // While loading, return empty array to prevent flash of default items
    if (isLoadingNav || !buttons || buttons.length === 0) {
      return [];
    }

    const isCommunityEnabled = siteSettings?.community_enabled !== false;

    return buttons
      .filter((btn) => {
        if (!btn.visible) return false;
        // Filter disabled buttons (enabled=false means completely hidden for non-admins)
        if (btn.enabled === false) return false;
        // Filter by login state
        if (user && !btn.show_when_logged_in) return false;
        if (!user && !btn.show_when_logged_out) return false;
        // Filter community links when community is disabled
        if (!isCommunityEnabled && btn.link === "/community") return false;
        return true;
      })
      .map((btn) => ({
        to: btn.link,
        icon: getIconComponent(btn.icon),
        label: getLocalizedLabel(btn),
        showOnDesktop: btn.show_on_desktop,
        showOnTablet: btn.show_on_tablet,
        showOnMobile: btn.show_on_mobile,
      }));
  }, [buttons, t, user, i18n.language, siteSettings?.community_enabled, isLoadingNav]);

  const handleSignOut = useCallback(() => {
    signOut();
    setMobileMenuOpen(false);
  }, [signOut]);

  const closeMobileMenu = useCallback(() => {
    setMobileMenuOpen(false);
  }, []);

  // Determine current device type based on window width
  const [deviceType, setDeviceType] = useState<'desktop' | 'tablet' | 'mobile'>('desktop');

  useEffect(() => {
    const updateDeviceType = () => {
      const width = window.innerWidth;
      if (width < 768) {
        setDeviceType('mobile');
      } else if (width < 1024) {
        setDeviceType('tablet');
      } else {
        setDeviceType('desktop');
      }
    };

    updateDeviceType();
    window.addEventListener('resize', updateDeviceType);
    return () => window.removeEventListener('resize', updateDeviceType);
  }, []);

  // Get device-specific settings
  const deviceSettings = useMemo(() => {
    return getDeviceSettings(navSettings, deviceType);
  }, [navSettings, deviceType]);

  const { 
    background_opacity: bgOpacity, 
    background_color: bgColor, 
    text_color: textColor, 
    hover_bg_color: hoverBgColor, 
    hover_text_color: hoverTextColor, 
    shadow_enabled: shadowEnabled 
  } = deviceSettings;

  // Use inline style for dynamic opacity - Tailwind arbitrary classes don't work with dynamic values
  const getNavBgInlineStyle = (): React.CSSProperties => {
    let bgColorValue = "transparent";
    if (bgColor === "white") bgColorValue = `rgba(255, 255, 255, ${bgOpacity})`;
    else if (bgColor === "black") bgColorValue = `rgba(0, 0, 0, ${bgOpacity})`;
    else if (bgColor === "primary") bgColorValue = `rgba(220, 38, 38, ${bgOpacity})`; // primary color
    return { backgroundColor: bgColorValue };
  };

  const getTextColorClass = () => {
    if (textColor === "white") return "text-white";
    if (textColor === "black") return "text-black";
    return "text-primary";
  };

  const getHoverClasses = () => {
    const bgClass = hoverBgColor === "white" ? "hover:bg-white" : hoverBgColor === "primary" ? "hover:bg-primary" : "hover:bg-black";
    const textClass = hoverTextColor === "white" ? "hover:text-white" : hoverTextColor === "primary" ? "hover:text-primary" : "hover:text-black";
    return `${bgClass} ${textClass}`;
  };

  const navBgStyle: React.CSSProperties = useDarkText
    ? { backgroundColor: "rgba(255, 255, 255, 0.85)" }
    : getNavBgInlineStyle();

  const navLinkClass = useDarkText
    ? "text-foreground hover:text-foreground/70"
    : "text-white hover:text-white/80";

  return <nav className={`fixed top-0 left-0 right-0 z-50 backdrop-blur-md transition-all duration-300 ${useDarkText ? "border-b border-border/40 shadow-[0_2px_20px_rgba(0,0,0,0.06)]" : `border-b border-white/20 dark:border-white/10 ${shadowEnabled ? "shadow-[0_2px_20px_rgba(0,0,0,0.08)]" : ""}`}`} style={navBgStyle}>
      {/* 顶部高光渐变 - 增加玻璃质感 */}
      {!useDarkText && <div className="absolute inset-0 bg-gradient-to-b from-white/10 via-transparent to-transparent pointer-events-none" />}
      <div className="relative w-full px-3 sm:px-4 lg:px-6 h-14 sm:h-16 flex items-center justify-between">
        <Link to="/" className="flex items-center gap-2">
          {logoUrl && (
            <img
              src={logoUrl}
              alt="Logo"
              style={{ width: logoWidth, height: logoHeight }}
              className="object-contain"
            />
          )}
        </Link>

        {/* Desktop Navigation - Only show on large screens */}
        <div className="hidden lg:flex items-center gap-6">
          {navItems.filter(item => item.showOnDesktop !== false).map(item => <PrefetchLink key={item.to} to={item.to} onClick={() => { if (item.to.startsWith('/restaurants')) clearRestaurantFilters(); }} className={`flex items-center gap-2 ${navLinkClass} px-3 py-1.5 rounded-md transition-colors`}>
              <item.icon className="w-4 h-4" />
              <span>{item.label}</span>
            </PrefetchLink>)}
        </div>

        <div className="flex items-center gap-1 sm:gap-3">


          <LanguageSwitcher className={useDarkText ? "text-foreground hover:bg-accent hover:text-accent-foreground" : "text-white hover:bg-white/20 hover:text-white"} />
          
          {user && <NotificationsDropdown />}
          
          {user ? <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="ghost" size="icon" className={`rounded-full h-8 w-8 sm:h-10 sm:w-10 ${useDarkText ? "" : "text-white hover:bg-white/20"}`}>
                  <Avatar className="w-7 h-7 sm:w-8 sm:h-8">
                    <AvatarImage src={profile?.avatar_url || user.user_metadata?.avatar_url} />
                    <AvatarFallback className="text-xs sm:text-sm">
                      {profile?.display_name?.[0]?.toUpperCase() || user.user_metadata?.display_name?.[0]?.toUpperCase() || user.email?.[0]?.toUpperCase()}
                    </AvatarFallback>
                  </Avatar>
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                <DropdownMenuLabel>{t("nav.myAccount")}</DropdownMenuLabel>
                <DropdownMenuSeparator />
                <DropdownMenuItem asChild>
                  <PrefetchLink to="/profile" className="cursor-pointer">
                    <User className="w-4 h-4 mr-2" />
                    {t("nav.profile")}
                  </PrefetchLink>
                </DropdownMenuItem>
                {isMerchant && <DropdownMenuItem asChild>
                    <PrefetchLink to="/merchant-dashboard/coupon-query" className="cursor-pointer">
                      <Ticket className="w-4 h-4 mr-2" />
                      {t("nav.couponQuery")}
                    </PrefetchLink>
                  </DropdownMenuItem>}
                {(isAdmin || isMerchant || isSupervisor || canAccessMerchantDashboard) && <DropdownMenuItem asChild>
                    <PrefetchLink to="/dashboard" className="cursor-pointer">
                      <Shield className="w-4 h-4 mr-2" />
                      {t("nav.dashboard")}
                    </PrefetchLink>
                  </DropdownMenuItem>}
                <DropdownMenuSeparator />
                <DropdownMenuItem onClick={() => signOut()} className="cursor-pointer">
                  <LogOut className="w-4 h-4 mr-2" />
                  {t("nav.signOut")}
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu> : <Button asChild className={`flex h-8 px-4 text-sm rounded-full lg:rounded-md ${useDarkText ? "bg-foreground text-background hover:bg-foreground/90" : "bg-black text-white hover:bg-black/90"} dark:bg-white dark:text-black dark:hover:bg-white/90`}>
              <PrefetchLink to="/auth">{t("nav.signIn")}</PrefetchLink>
            </Button>}

          {/* Tablet Menu (hidden on mobile, webview, shown on tablet) */}
          {!isWebView && (
            <Sheet open={mobileMenuOpen} onOpenChange={setMobileMenuOpen}>
              <SheetTrigger asChild className="hidden md:flex lg:hidden">
                <Button size="icon" aria-label={t("nav.openMenu")} className={`h-8 w-8 sm:h-10 sm:w-10 rounded-lg flex items-center justify-center ${useDarkText ? "bg-foreground text-background hover:bg-foreground/80" : "bg-white/20 text-white hover:bg-white/30"} dark:bg-background dark:text-foreground dark:border dark:border-border dark:hover:bg-muted`}>
                  <Menu className="w-4 h-4 sm:w-5 sm:h-5" />
                </Button>
              </SheetTrigger>
              <SheetContent side="right" className="w-64 sm:w-80">
              <VisuallyHidden>
                <SheetTitle>{t("nav.menu")}</SheetTitle>
              </VisuallyHidden>
              <div className="flex flex-col gap-4 mt-8">
                {navItems.filter(item => item.showOnMobile !== false).map(item => <PrefetchLink key={item.to} to={item.to} onClick={() => { if (item.to.startsWith('/restaurants')) clearRestaurantFilters(); closeMobileMenu(); }} className="flex items-center gap-3 text-lg text-muted-foreground hover:text-primary transition-colors">
                    <item.icon className="w-5 h-5" />
                    <span>{item.label}</span>
                  </PrefetchLink>)}
                
                <div className="border-t border-border my-4" />
                
                {user ? <>
                    <PrefetchLink to="/profile" onClick={closeMobileMenu} className="flex items-center gap-3 text-lg text-muted-foreground hover:text-primary transition-colors">
                      <User className="w-5 h-5" />
                      <span>{t("nav.profile")}</span>
                    </PrefetchLink>
                    {(isAdmin || isMerchant || isSupervisor || canAccessMerchantDashboard) && <PrefetchLink to="/dashboard" onClick={closeMobileMenu} className="flex items-center gap-3 text-lg text-muted-foreground hover:text-primary transition-colors">
                        <Shield className="w-5 h-5" />
                        <span>{t("nav.dashboard")}</span>
                      </PrefetchLink>}
                    <button onClick={handleSignOut} className="flex items-center gap-3 text-lg text-muted-foreground hover:text-primary transition-colors">
                      <LogOut className="w-5 h-5" />
                      <span>{t("nav.signOut")}</span>
                    </button>
                  </> : <PrefetchLink to="/auth" onClick={closeMobileMenu} className="flex items-center gap-3 text-lg text-muted-foreground hover:text-primary transition-colors">
                    <User className="w-5 h-5" />
                    <span>{t("nav.signIn")}</span>
                  </PrefetchLink>}
              </div>
            </SheetContent>
          </Sheet>
          )}
        </div>
      </div>
    </nav>;
};
export default Navigation;
