import { Skeleton } from "@/components/ui/skeleton";

interface CommunityListSkeletonProps {
  count?: number;
}

const CommunityListSkeleton = ({ count = 8 }: CommunityListSkeletonProps) => {
  return (
    <div className="container mx-auto px-4 py-6 animate-skeleton-fade-in">
      {/* Tabs */}
      <div className="flex gap-2 mb-6">
        <Skeleton className="h-9 w-24 rounded-md" />
        <Skeleton className="h-9 w-24 rounded-md" />
      </div>

      {/* Grid */}
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
        {Array.from({ length: count }).map((_, i) => (
          <div key={i} className="rounded-lg overflow-hidden border border-border bg-card">
            <Skeleton className="w-full aspect-square rounded-none" />
            <div className="p-3 space-y-2">
              <Skeleton className="h-4 w-full" />
              <Skeleton className="h-4 w-2/3" />
              <div className="flex items-center gap-2 pt-1">
                <Skeleton className="h-6 w-6 rounded-full" />
                <Skeleton className="h-3 w-20" />
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default CommunityListSkeleton;
