import { createContext, useContext, useState, useCallback, useRef, useEffect, ReactNode } from "react";
import { supabase } from "@/integrations/supabase/client";
import type { AIRecipeSuggestion } from "@/hooks/useAIRecipe";

const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL;
const ANON_KEY = import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY;
const VIDEO_URL = `${SUPABASE_URL}/functions/v1/ai-recipe-video`;

const MAX_CONCURRENT = 2;

export type BGVideoStatus = "creating" | "processing" | "succeeded" | "failed";

export interface BGVideoTask {
  id: string; // unique id
  taskId: string; // backend task id
  recipeName: string;
  recipeNameEn?: string;
  imageUrl: string;
  status: BGVideoStatus;
  videoUrl: string | null;
  /** URL of the watermarked video in storage (persistent) */
  watermarkedVideoUrl: string | null;
  error: string | null;
  createdAt: number;
  /** Has the user viewed this completed task */
  viewed: boolean;
  /** Full recipe data for opening detail dialog from widget */
  recipeData?: AIRecipeSuggestion;
}

interface VideoTaskContextType {
  tasks: BGVideoTask[];
  addTask: (recipeName: string, recipeNameEn: string | undefined, imageUrl: string, prompt: string, recipeData?: AIRecipeSuggestion) => Promise<string | false>;
  markViewed: (id: string) => void;
  removeTask: (id: string) => void;
  /** Update the watermarked video URL for a task */
  setTaskWatermarkedUrl: (id: string, url: string) => void;
  showGuideAnimation: boolean;
  clearGuideAnimation: () => void;
  activeCount: number;
}

const VideoTaskContext = createContext<VideoTaskContextType | null>(null);

export const useVideoTasks = () => {
  const ctx = useContext(VideoTaskContext);
  if (!ctx) throw new Error("useVideoTasks must be used within VideoTaskProvider");
  return ctx;
};

export const VideoTaskProvider = ({ children }: { children: ReactNode }) => {
  const [tasks, setTasks] = useState<BGVideoTask[]>([]);
  const [showGuideAnimation, setShowGuideAnimation] = useState(false);
  const pollTimers = useRef<Record<string, number>>({});

  const updateTask = useCallback((id: string, patch: Partial<BGVideoTask>) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, ...patch } : t));
  }, []);

  const pollTask = useCallback(async (task: BGVideoTask) => {
    const timerKey = task.id;
    try {
      console.log(`[VideoTask] Polling task ${task.id}, taskId=${task.taskId}`);
      const resp = await fetch(`${VIDEO_URL}/${task.taskId}`, {
        headers: { Authorization: `Bearer ${ANON_KEY}` },
      });
      if (!resp.ok) throw new Error(`Poll failed ${resp.status}`);
      const data = await resp.json();
      console.log(`[VideoTask] Poll result for ${task.id}:`, data.status, JSON.stringify(data.content));

      if (data.status === "succeeded") {
        const videoUrl =
          data.content?.video_url ||
          data.content?.[0]?.url ||
          data.content?.[0]?.video_url ||
          null;
        console.log(`[VideoTask] Resolved videoUrl:`, videoUrl);
        updateTask(task.id, { status: "succeeded", videoUrl });
        delete pollTimers.current[timerKey];
      } else if (data.status === "failed") {
        updateTask(task.id, { status: "failed", error: data.error?.message || "视频生成失败" });
        delete pollTimers.current[timerKey];
      } else {
        pollTimers.current[timerKey] = window.setTimeout(() => {
          // Re-read the task from state
          setTasks(prev => {
            const t = prev.find(x => x.id === task.id);
            if (t && (t.status === "creating" || t.status === "processing")) {
              pollTask(t);
            }
            return prev;
          });
        }, 6000);
      }
    } catch (err) {
      console.error("Poll video task error:", err);
      updateTask(task.id, { status: "failed", error: "查询视频状态失败" });
      delete pollTimers.current[timerKey];
    }
  }, [updateTask]);

  const addTask = useCallback(async (recipeName: string, recipeNameEn: string | undefined, imageUrl: string, prompt: string, recipeData?: AIRecipeSuggestion): Promise<string | false> => {
    // Check concurrent limit
    const activeTasks = tasks.filter(t => t.status === "creating" || t.status === "processing");
    if (activeTasks.length >= MAX_CONCURRENT) return false;

    const id = `vt_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`;
    const newTask: BGVideoTask = {
      id,
      taskId: "",
      recipeName,
      recipeNameEn,
      imageUrl,
      status: "creating",
      videoUrl: null,
      watermarkedVideoUrl: null,
      error: null,
      createdAt: Date.now(),
      viewed: false,
      recipeData,
    };

    setTasks(prev => [...prev, newTask]);
    setShowGuideAnimation(true);

    try {
      const { data: { user } } = await supabase.auth.getUser();
      const resp = await fetch(VIDEO_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${ANON_KEY}`,
        },
        body: JSON.stringify({
          image_url: imageUrl,
          prompt,
          user_id: user?.id || null,
          recipe_name: recipeName,
        }),
      });

      if (!resp.ok) {
        const errData = await resp.json().catch(() => ({}));
        if (resp.status === 429 && errData.error === "daily_limit_reached") {
          throw new Error(errData.message || "今日视频生成次数已达上限");
        }
        throw new Error(errData.error || `Error ${resp.status}`);
      }

      const data = await resp.json();
      const taskId = data.id;
      if (!taskId) throw new Error("No task ID returned");

      const updatedTask = { ...newTask, taskId, status: "processing" as const };
      updateTask(id, { taskId, status: "processing" });

      // Start polling
      pollTimers.current[id] = window.setTimeout(() => pollTask(updatedTask), 6000);
      return id;
    } catch (err: any) {
      console.error("Generate video error:", err);
      updateTask(id, { status: "failed", error: err.message || "创建视频任务失败" });
      return false;
    }
  }, [tasks, updateTask, pollTask]);

  const markViewed = useCallback((id: string) => {
    updateTask(id, { viewed: true });
  }, [updateTask]);

  const setTaskWatermarkedUrl = useCallback((id: string, url: string) => {
    updateTask(id, { watermarkedVideoUrl: url });
  }, [updateTask]);

  const removeTask = useCallback((id: string) => {
    if (pollTimers.current[id]) {
      clearTimeout(pollTimers.current[id]);
      delete pollTimers.current[id];
    }
    setTasks(prev => prev.filter(t => t.id !== id));
  }, []);

  const clearGuideAnimation = useCallback(() => {
    setShowGuideAnimation(false);
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      Object.values(pollTimers.current).forEach(t => clearTimeout(t));
    };
  }, []);

  const activeCount = tasks.filter(t =>
    t.status === "creating" || t.status === "processing" || (t.status === "succeeded" && !t.viewed)
  ).length;

  return (
    <VideoTaskContext.Provider value={{
      tasks,
      addTask,
      markViewed,
      removeTask,
      setTaskWatermarkedUrl,
      showGuideAnimation,
      clearGuideAnimation,
      activeCount,
    }}>
      {children}
    </VideoTaskContext.Provider>
  );
};
