import { Link } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { useState } from "react";
import { Bell, CheckCheck, Trash2, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { useNotifications, useUnreadCount, useMarkAsRead, useMarkAllAsRead, useClearAllNotifications, Notification } from "@/hooks/useNotifications";
import { formatDistanceToNow } from "date-fns";
import { zhCN, enUS, pt } from "date-fns/locale";

const getDateLocale = (lang: string) => {
  switch (lang) {
    case "zh": return zhCN;
    case "pt": return pt;
    default: return enUS;
  }
};

/**
 * Fallback translations for legacy Chinese-only notifications.
 */
const LEGACY_TRANSLATIONS: Record<string, { en: string; pt: string }> = {
  "帖子发布成功": { en: "Post published", pt: "Postagem publicada" },
  "您的帖子已通过审核并发布": { en: "Your post has been approved and published", pt: "Sua postagem foi aprovada e publicada" },
  "帖子未能发布": { en: "Post not published", pt: "Postagem não publicada" },
  "您的帖子因内容不符合规范未能发布，请修改后重新提交": { en: "Your post was not approved. Please revise and resubmit.", pt: "Sua postagem não foi aprovada. Por favor, revise e reenvie." },
  "恭喜获得积分！": { en: "Congratulations! You earned points!", pt: "Parabéns! Você ganhou pontos!" },
  "积分发放通知": { en: "Points notification", pt: "Notificação de pontos" },
  "积分扣除通知": { en: "Points deduction notification", pt: "Notificação de dedução de pontos" },
  "积分兑换成功": { en: "Points exchange successful", pt: "Troca de pontos bem-sucedida" },
  "评论已被删除": { en: "Comment removed", pt: "Comentário removido" },
  "邀请码申请已通过": { en: "Invitation Code Application Approved", pt: "Solicitação de código de convite aprovada" },
  "邀请码申请被拒绝": { en: "Invitation Code Application Rejected", pt: "Solicitação de código de convite rejeitada" },
};

const parseMultiLang = (raw: string, lang: string): string => {
  if (!raw) return raw;

  if (raw.startsWith("[[MULTILANG]]")) {
    try {
      const json = JSON.parse(raw.slice("[[MULTILANG]]".length));
      return json[lang] || json["en"] || raw;
    } catch {
      return raw;
    }
  }

  if (lang !== "zh" && LEGACY_TRANSLATIONS[raw]) {
    return LEGACY_TRANSLATIONS[raw][lang as "en" | "pt"] || raw;
  }

  if (lang !== "zh") {
    for (const [zh, translations] of Object.entries(LEGACY_TRANSLATIONS)) {
      if (raw.startsWith(zh)) {
        const rest = raw.slice(zh.length);
        return (translations[lang as "en" | "pt"] || zh) + rest;
      }
    }
  }

  return raw;
};

const NotificationsDropdown = () => {
  const { t, i18n } = useTranslation();
  const { data: notifications = [] } = useNotifications();
  const { data: unreadCount = 0 } = useUnreadCount();
  const markAsRead = useMarkAsRead();
  const markAllAsRead = useMarkAllAsRead();
  const clearAll = useClearAllNotifications();
  const dateLocale = getDateLocale(i18n.language);
  const [detailNotification, setDetailNotification] = useState<Notification | null>(null);

  const handleNotificationClick = (notification: Notification) => {
    if (!notification.read) {
      markAsRead.mutate(notification.id);
    }
    // If no link, open detail dialog
    if (!notification.link) {
      setDetailNotification(notification);
    }
  };

  const getNotificationIcon = (type: string) => {
    switch (type) {
      case "comment_reply": return "💬";
      case "new_activity": return "🎉";
      case "activity_update": return "📝";
      case "new_user": return "👋";
      case "merchant_joined": return "🏪";
      default: return "🔔";
    }
  };

  const renderNotificationItem = (notification: Notification) => {
    const content = (
      <div className="flex items-start gap-2 w-full">
        <span className="text-2xl shrink-0">{getNotificationIcon(notification.type)}</span>
        <div className="flex-1 min-w-0 overflow-hidden">
          <div className="flex items-center justify-between gap-2">
            <p className="font-semibold text-sm line-clamp-2 break-words">
              {parseMultiLang(notification.title, i18n.language)}
            </p>
            {!notification.read && (
              <Badge variant="default" className="h-2 w-2 p-0 rounded-full shrink-0" />
            )}
          </div>
          <p className="text-xs text-muted-foreground line-clamp-2 mt-1 break-words">
            {parseMultiLang(notification.content, i18n.language)}
          </p>
          <p className="text-xs text-muted-foreground mt-1">
            {formatDistanceToNow(new Date(notification.created_at), {
              addSuffix: true,
              locale: dateLocale,
            })}
          </p>
        </div>
      </div>
    );

    if (notification.link) {
      return (
        <DropdownMenuItem
          key={notification.id}
          className={`flex flex-col items-start p-3 cursor-pointer ${
            !notification.read ? "bg-secondary/50" : ""
          }`}
          asChild
        >
          <Link
            to={notification.link}
            onClick={() => handleNotificationClick(notification)}
          >
            {content}
          </Link>
        </DropdownMenuItem>
      );
    }

    return (
      <DropdownMenuItem
        key={notification.id}
        className={`flex flex-col items-start p-3 cursor-pointer ${
          !notification.read ? "bg-secondary/50" : ""
        }`}
        onClick={() => handleNotificationClick(notification)}
      >
        {content}
      </DropdownMenuItem>
    );
  };

  return (
    <>
      <DropdownMenu>
        <DropdownMenuTrigger asChild>
          <Button variant="ghost" size="icon" className="relative text-black hover:bg-black hover:text-white transition-colors">
            <Bell className="h-5 w-5" />
            {unreadCount > 0 && (
              <Badge
                variant="destructive"
                className="absolute -top-1 -right-1 h-5 w-5 flex items-center justify-center p-0 text-xs"
              >
                {unreadCount > 9 ? "9+" : unreadCount}
              </Badge>
            )}
          </Button>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="end" className="w-80 max-h-[500px]">
          <DropdownMenuLabel className="flex items-center justify-between">
            <span>{t("notifications.title")}</span>
            <div className="flex items-center gap-1">
              {unreadCount > 0 && (
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => markAllAsRead.mutate()}
                  disabled={markAllAsRead.isPending}
                >
                  <CheckCheck className="h-4 w-4 mr-1" />
                  {t("notifications.markAllRead")}
                </Button>
              )}
              {notifications.length > 0 && (
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => clearAll.mutate()}
                  disabled={clearAll.isPending}
                  className="text-destructive hover:text-destructive"
                >
                  <Trash2 className="h-4 w-4" />
                </Button>
              )}
            </div>
          </DropdownMenuLabel>
          <DropdownMenuSeparator />
          <ScrollArea className="h-[400px]">
            {notifications.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                {t("notifications.noNotifications")}
              </div>
            ) : (
              notifications.map(renderNotificationItem)
            )}
          </ScrollArea>
        </DropdownMenuContent>
      </DropdownMenu>

      {/* Detail Dialog for system notifications */}
      <Dialog open={!!detailNotification} onOpenChange={(open) => !open && setDetailNotification(null)}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2 text-base">
              <span className="text-2xl">{detailNotification ? getNotificationIcon(detailNotification.type) : "🔔"}</span>
              <span className="break-words">
                {detailNotification && parseMultiLang(detailNotification.title, i18n.language)}
              </span>
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-3">
            <p className="text-sm text-foreground whitespace-pre-wrap break-words leading-relaxed">
              {detailNotification && parseMultiLang(detailNotification.content, i18n.language)}
            </p>
            <p className="text-xs text-muted-foreground">
              {detailNotification && formatDistanceToNow(new Date(detailNotification.created_at), {
                addSuffix: true,
                locale: dateLocale,
              })}
            </p>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
};

export default NotificationsDropdown;
