import { useMemo } from 'react';
import {
  isCapacitorApp,
  isIOSWebView,
  isAndroidWebView,
  isInWebView,
  isIOSDevice,
  isIOSSafari,
} from '@/lib/externalLinks';

export type EnvironmentType = 
  | 'capacitor'        // Capacitor 原生应用
  | 'ios-safari'       // iOS Safari 浏览器
  | 'ios-webview'      // iOS 应用内嵌浏览器
  | 'android-webview'  // Android 应用内嵌浏览器
  | 'desktop-browser'  // 桌面浏览器（Windows/Mac/Linux）
  | 'android-browser'; // Android 普通浏览器（Chrome等）

export interface EnvironmentInfo {
  /** 当前环境类型 */
  type: EnvironmentType;
  /** 是否在 Capacitor 原生应用中 */
  isNativeApp: boolean;
  /** 是否在任何 WebView 中 */
  isWebView: boolean;
  /** 是否在 iOS WebView 中 */
  isIOSWebView: boolean;
  /** 是否在 Android WebView 中 */
  isAndroidWebView: boolean;
  /** 是否在标准浏览器中（非 WebView） */
  isBrowser: boolean;
  /** 是否是 iOS 设备 */
  isIOSDevice: boolean;
  /** 是否是 iOS Safari */
  isIOSSafari: boolean;
  /** 是否是 Android 设备 */
  isAndroidDevice: boolean;
  /** 是否是 Android 普通浏览器（非 WebView） */
  isAndroidBrowser: boolean;
  /** 是否是桌面设备 */
  isDesktop: boolean;
  /** 环境描述（可用于调试/显示） */
  description: string;
}

/**
 * 检测是否为 Android 设备
 */
const isAndroidDevice = (): boolean => {
  if (typeof navigator === 'undefined') return false;
  const ua = navigator.userAgent;
  return /Android/i.test(ua);
};

/**
 * 检测是否为桌面设备
 */
const isDesktopDevice = (): boolean => {
  if (typeof navigator === 'undefined') return false;
  const ua = navigator.userAgent;
  // 排除移动设备
  const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(ua);
  return !isMobile;
};

/**
 * 检测是否为 Android 普通浏览器（非 WebView）
 */
const isAndroidBrowser = (): boolean => {
  if (typeof navigator === 'undefined') return false;
  const ua = navigator.userAgent;
  // 是 Android 设备
  if (!/Android/i.test(ua)) return false;
  // 不是 WebView
  if (isAndroidWebView()) return false;
  // 不是 Capacitor
  if (isCapacitorApp()) return false;
  return true;
};

/**
 * 环境检测 Hook
 * 用于检测当前运行环境（浏览器/原生应用/WebView）
 * 
 * @example
 * const { type, description } = useEnvironment();
 * 
 * switch (type) {
 *   case 'desktop-browser':
 *     console.log('桌面浏览器'); // Chrome/Firefox/Edge on Windows/Mac
 *     break;
 *   case 'android-browser':
 *     console.log('Android 浏览器'); // Chrome on Android
 *     break;
 *   case 'ios-safari':
 *     console.log('iOS Safari'); // Safari on iPhone/iPad
 *     break;
 *   case 'ios-webview':
 *     console.log('iOS 内嵌浏览器'); // 微信/抖音等 App 内
 *     break;
 *   case 'android-webview':
 *     console.log('Android 内嵌浏览器'); // 微信/抖音等 App 内
 *     break;
 *   case 'capacitor':
 *     console.log('原生应用'); // 我们自己的 App
 *     break;
 * }
 */
export const useEnvironment = (): EnvironmentInfo => {
  return useMemo(() => {
    // Default values for SSR or restricted environments
    const defaultInfo: EnvironmentInfo = {
      type: 'desktop-browser',
      isNativeApp: false,
      isWebView: false,
      isIOSWebView: false,
      isAndroidWebView: false,
      isBrowser: true,
      isIOSDevice: false,
      isIOSSafari: false,
      isAndroidDevice: false,
      isAndroidBrowser: false,
      isDesktop: true,
      description: '桌面浏览器',
    };

    // Safely detect environment with try-catch for WebView compatibility
    try {
      // Check if we're in a browser environment
      if (typeof window === 'undefined' || typeof navigator === 'undefined') {
        return defaultInfo;
      }

      const capacitor = isCapacitorApp();
      const iosWebView = isIOSWebView();
      const androidWebView = isAndroidWebView();
      const webView = isInWebView();
      const iosDevice = isIOSDevice();
      const iosSafari = isIOSSafari();
      const androidDevice = isAndroidDevice();
      const androidBrowser = isAndroidBrowser();
      const desktop = isDesktopDevice();

      let type: EnvironmentType;
      let description: string;

      // 判断顺序：Capacitor -> iOS WebView -> iOS Safari -> Android WebView -> Android Browser -> Desktop
      if (capacitor) {
        type = 'capacitor';
        description = 'Capacitor 原生应用';
      } else if (iosWebView) {
        type = 'ios-webview';
        description = 'iOS 内嵌浏览器';
      } else if (iosSafari) {
        type = 'ios-safari';
        description = 'iOS Safari 浏览器';
      } else if (androidWebView) {
        type = 'android-webview';
        description = 'Android 内嵌浏览器';
      } else if (androidBrowser) {
        type = 'android-browser';
        description = 'Android 浏览器';
      } else {
        type = 'desktop-browser';
        description = '桌面浏览器';
      }

      return {
        type,
        isNativeApp: capacitor,
        isWebView: webView,
        isIOSWebView: iosWebView,
        isAndroidWebView: androidWebView,
        isBrowser: !capacitor && !webView,
        isIOSDevice: iosDevice,
        isIOSSafari: iosSafari,
        isAndroidDevice: androidDevice,
        isAndroidBrowser: androidBrowser,
        isDesktop: desktop,
        description,
      };
    } catch (error) {
      console.warn('[useEnvironment] Environment detection failed:', error);
      return defaultInfo;
    }
  }, []);
};

export default useEnvironment;
