import { useTranslation } from "react-i18next";
import { Link } from "react-router-dom";
import { Phone, Mail, MessageSquare, Globe, Megaphone } from "lucide-react";
import { useSiteSettings } from "@/hooks/useSiteSettings";
import { VERSION } from "@/lib/version";
import { useState } from "react";
import FeedbackDialog from "@/components/FeedbackDialog";
import xiaoxiongLogo from "@/assets/xiaoxiong-logo-footer.png";

const Footer = () => {
  const { t } = useTranslation();
  const { settings } = useSiteSettings();
  const [feedbackOpen, setFeedbackOpen] = useState(false);

  return (
    <footer className="border-t bg-card">
      <div className="container mx-auto px-4 py-6 sm:py-8">
        {/* Main Content Grid - 4 columns on desktop */}
        <div className="grid grid-cols-2 gap-6 sm:gap-8 md:grid-cols-4">
          {/* Brand */}
          <div className="col-span-2 md:col-span-1 space-y-2 sm:space-y-3">
            <h3 className="font-bold text-base sm:text-lg">{t("footer.brandName")}</h3>
            <p className="text-xs sm:text-sm text-muted-foreground leading-relaxed">
              {t("footer.description")}
            </p>
            {/* Contact inline on mobile, separate col on md */}
            <div className="space-y-1.5 text-xs sm:text-sm text-muted-foreground md:hidden">
              {settings?.contact_phone && (
                <a href={`tel:${settings.contact_phone}`} className="flex items-center gap-2 hover:text-foreground transition-colors">
                  <Phone className="h-3.5 w-3.5 flex-shrink-0" />
                  <span>{settings.contact_phone}</span>
                </a>
              )}
              {settings?.contact_email && (
                <a href={`mailto:${settings.contact_email}`} className="flex items-center gap-2 hover:text-foreground transition-colors">
                  <Mail className="h-3.5 w-3.5 flex-shrink-0" />
                  <span className="break-all">{settings.contact_email}</span>
                </a>
              )}
            </div>
          </div>

          {/* Contact Info - hidden on mobile (shown inline above) */}
          <div className="hidden md:block space-y-2 sm:space-y-3">
            <h4 className="font-semibold text-sm sm:text-base">{t("footer.contact")}</h4>
            <div className="space-y-1.5 sm:space-y-2 text-xs sm:text-sm text-muted-foreground">
              {settings?.contact_phone && (
                <a href={`tel:${settings.contact_phone}`} className="flex items-center gap-2 hover:text-foreground transition-colors">
                  <Phone className="h-3.5 w-3.5 sm:h-4 sm:w-4 flex-shrink-0" />
                  <span>{settings.contact_phone}</span>
                </a>
              )}
              {settings?.contact_email && (
                <a href={`mailto:${settings.contact_email}`} className="flex items-center gap-2 hover:text-foreground transition-colors">
                  <Mail className="h-3.5 w-3.5 sm:h-4 sm:w-4 flex-shrink-0" />
                  <span className="break-all">{settings.contact_email}</span>
                </a>
              )}
            </div>
          </div>

          {/* Links */}
          <div className="space-y-2 sm:space-y-3">
            <h4 className="font-semibold text-sm sm:text-base">{t("footer.links")}</h4>
            <nav className="flex flex-col gap-1.5 sm:gap-2 text-xs sm:text-sm">
              <Link to="/about-us" className="text-muted-foreground hover:text-foreground transition-colors">
                {t("footer.aboutUs")}
              </Link>
              <Link to="/privacy-policy" className="text-muted-foreground hover:text-foreground transition-colors">
                {t("footer.privacyPolicy")}
              </Link>
              <Link to="/terms-of-service" className="text-muted-foreground hover:text-foreground transition-colors">
                {t("footer.termsOfService")}
              </Link>
              <Link to="/join-us" className="text-muted-foreground hover:text-foreground transition-colors">
                {t("footer.joinUs")}
              </Link>
              <a href="https://xiaoxiong.pt/" target="_blank" rel="noopener noreferrer"
                className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground transition-colors">
                <Globe className="h-3.5 w-3.5" />
                {t("footer.officialWebsite")}
              </a>
            </nav>
          </div>

          {/* Business / Ad Space */}
          <div className="space-y-2 sm:space-y-3">
            <h4 className="font-semibold text-sm sm:text-base">{t("footer.business")}</h4>
            <nav className="flex flex-col gap-1.5 sm:gap-2 text-xs sm:text-sm">
              <Link to="/ad-space" className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground transition-colors">
                <Megaphone className="h-3.5 w-3.5" />
                {t("footer.adSpace")}
              </Link>
              <a href="https://v.xiaoxiong.pt:8000/manager.html#/" target="_blank" rel="noopener noreferrer"
                className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground transition-colors">
                <Globe className="h-3.5 w-3.5" />
                {t("footer.demo")}
              </a>
              <button
                onClick={() => setFeedbackOpen(true)}
                className="inline-flex items-center gap-1.5 text-muted-foreground hover:text-foreground transition-colors text-left"
              >
                <MessageSquare className="h-3.5 w-3.5 flex-shrink-0" />
                {t("feedback.title")}
              </button>
            </nav>
          </div>
        </div>

        {/* Bottom Section */}
        <div className="mt-6 sm:mt-8 pt-4 sm:pt-6 border-t flex flex-col items-center gap-2 sm:gap-3">
          <div className="flex flex-col sm:flex-row items-center justify-center gap-1 sm:gap-3 text-xs text-muted-foreground">
            <span className="text-center">
              © {new Date().getFullYear()} {t("footer.brandName")}. {t("footer.allRightsReserved")}
            </span>
            <span className="hidden sm:inline opacity-50">•</span>
            <span className="opacity-70">v{VERSION.app}</span>
          </div>
          <img src={xiaoxiongLogo} alt="XIAOXIONG Logo" width={132} height={16} className="h-3 sm:h-4 object-contain" />
        </div>
      </div>

      <FeedbackDialog open={feedbackOpen} onOpenChange={setFeedbackOpen} />
    </footer>
  );
};

export default Footer;
