// Detect if running in a Capacitor native app
export const isCapacitorApp = (): boolean => {
  try {
    if (typeof window === 'undefined') return false;
    const cap = (window as any).Capacitor;
    if (!cap) return false;
    
    // Check method form (Capacitor 3+)
    if (typeof cap.isNativePlatform === 'function') {
      return cap.isNativePlatform();
    }
    
    // Check property form (some versions)
    if (typeof cap.isNativePlatform === 'boolean') {
      return cap.isNativePlatform;
    }
    
    // Check isNative property (legacy compatibility)
    if (typeof cap.isNative === 'boolean') {
      return cap.isNative;
    }
    
    // Check platform property
    if (cap.getPlatform && typeof cap.getPlatform === 'function') {
      const platform = cap.getPlatform();
      return platform === 'ios' || platform === 'android';
    }
    
    // If Capacitor object exists but no detection methods, assume it's native
    return true;
  } catch {
    return false;
  }
};

// Detect if running in iOS WebView (WKWebView)
export const isIOSWebView = (): boolean => {
  try {
    // If it's a Capacitor app, don't treat as generic WebView
    if (isCapacitorApp()) return false;
    
    if (typeof navigator === 'undefined') return false;
    const ua = navigator.userAgent;
    const isIOS = /iPad|iPhone|iPod/.test(ua);
    
    if (!isIOS) return false;
    
    // PWA standalone mode is not WebView
    if (typeof window !== 'undefined') {
      const isStandalone = (window.navigator as any).standalone === true;
      if (isStandalone) return false;
    }
    
    // Check for common in-app browsers (WeChat, QQ, Facebook, Instagram, etc.)
    const isInAppBrowser = /FBAN|FBAV|Twitter|Instagram|Line|WeChat|MicroMessenger|QQ|Weibo|Douyin|TikTok|Alipay|DingTalk|Xiaohongshu/i.test(ua);
    if (isInAppBrowser) return true;
    
    // WKWebView detection - check for missing Safari identifier
    const hasSafari = /Safari\//.test(ua);
    const hasChrome = /CriOS/.test(ua);
    const hasFirefox = /FxiOS/.test(ua);
    const hasEdge = /EdgiOS/.test(ua);
    
    // If iOS but no browser identifier, it's likely a WebView
    if (!hasSafari && !hasChrome && !hasFirefox && !hasEdge) return true;
    
    // Some WebViews include Safari but lack Version/ (Safari has "Version/X.X")
    const hasVersion = /Version\/[\d.]+/.test(ua);
    if (hasSafari && !hasVersion && !hasChrome && !hasFirefox && !hasEdge) return true;
    
    return false;
  } catch {
    return false;
  }
};

// Check if the device is iOS (Safari or any iOS browser)
export const isIOSDevice = (): boolean => {
  try {
    if (typeof navigator === 'undefined') return false;
    const ua = navigator.userAgent;
    return /iPad|iPhone|iPod/.test(ua) || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
  } catch {
    return false;
  }
};

// Check if running in iOS Safari (not WebView)
export const isIOSSafari = (): boolean => {
  try {
    if (!isIOSDevice()) return false;
    if (isIOSWebView()) return false;
    if (isCapacitorApp()) return false;
    
    if (typeof navigator === 'undefined') return false;
    const ua = navigator.userAgent;
    
    // Exclude third-party iOS browsers that may include Version/ and Safari/
    const isThirdPartyBrowser = /CriOS|FxiOS|EdgiOS|OPiOS|GSA\//.test(ua);
    if (isThirdPartyBrowser) return false;
    
    // Safari has both "Safari/" and "Version/" in UA
    return /Safari\//.test(ua) && /Version\/[\d.]+/.test(ua);
  } catch {
    return false;
  }
};

// Detect if running in Android WebView
export const isAndroidWebView = (): boolean => {
  try {
    if (typeof navigator === 'undefined') return false;
    const ua = navigator.userAgent;
    const isAndroid = /Android/.test(ua);
    // Android WebView typically has "wv" in the UA string
    const isWebView = /wv/.test(ua) || /Version\/[\d.]+.*Chrome/.test(ua);
    
    return isAndroid && isWebView;
  } catch {
    return false;
  }
};

// Check if in any WebView
export const isInWebView = (): boolean => {
  try {
    // Capacitor apps run in WebView technically, but we treat them as native apps
    if (isCapacitorApp()) return false;
    return isIOSWebView() || isAndroidWebView();
  } catch {
    return false;
  }
};

// Try to open URL with fallback for WebView environments
export const openExternalUrl = (url: string, options?: {
  fallbackUrl?: string;
  useSameWindow?: boolean;
}): void => {
  const { fallbackUrl, useSameWindow = false } = options || {};
  
  if (isIOSWebView()) {
    // In iOS WebView, window.open is often blocked
    // Use location.href for same-window navigation
    if (useSameWindow) {
      window.location.href = url;
      return;
    }
    
    // Try to open in new window first
    const newWindow = window.open(url, '_blank');
    
    // If blocked, fall back to location.href or iframe trick
    if (!newWindow || newWindow.closed) {
      if (fallbackUrl) {
        window.location.href = fallbackUrl;
      } else {
        // Use location.href as last resort
        window.location.href = url;
      }
    }
  } else {
    // Standard browser behavior
    window.open(url, '_blank');
  }
};

// Open URL scheme (maps://, tel://, mailto://, etc.) with WebView compatibility
export const openUrlScheme = (
  schemeUrl: string, 
  universalLinkFallback?: string
): void => {
  if (isIOSWebView()) {
    // In iOS WebView, URL schemes need special handling
    const start = Date.now();
    const timeout = 1500;
    let didNavigate = false;
    
    const handleVisibilityChange = () => {
      if (document.hidden) {
        didNavigate = true;
      }
    };
    
    document.addEventListener('visibilitychange', handleVisibilityChange);
    
    // Try to open the scheme URL
    window.location.href = schemeUrl;
    
    // Check after timeout if navigation happened
    setTimeout(() => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      
      if (!didNavigate && universalLinkFallback && Date.now() - start >= timeout) {
        // Scheme didn't work, try universal link
        window.location.href = universalLinkFallback;
      }
    }, timeout);
  } else if (isAndroidWebView()) {
    // Android WebView - try intent URL or direct navigation
    window.location.href = schemeUrl;
  } else {
    // Standard browser - can use window.open
    window.open(schemeUrl, '_blank');
  }
};
