import { Skeleton } from "@/components/ui/skeleton";

const RecipeDetailSkeleton = () => {
  return (
    <div className="min-h-screen bg-background animate-skeleton-fade-in">
      {/* Hero image */}
      <Skeleton className="w-full h-[40vh] rounded-none" />

      <div className="container mx-auto max-w-3xl px-4 -mt-12 relative z-10">
        <div className="bg-card rounded-lg border border-border p-6 space-y-6 shadow-lg">
          {/* Title + meta */}
          <div className="space-y-3">
            <Skeleton className="h-8 w-3/4" />
            <div className="flex flex-wrap gap-4">
              <Skeleton className="h-5 w-20" />
              <Skeleton className="h-5 w-24" />
              <Skeleton className="h-5 w-20" />
            </div>
          </div>

          {/* Tags */}
          <div className="flex gap-2 flex-wrap">
            <Skeleton className="h-6 w-16 rounded-full" />
            <Skeleton className="h-6 w-20 rounded-full" />
            <Skeleton className="h-6 w-14 rounded-full" />
          </div>

          {/* Ingredients */}
          <div className="space-y-3">
            <Skeleton className="h-6 w-32" />
            <div className="grid grid-cols-2 gap-2">
              {Array.from({ length: 8 }).map((_, i) => (
                <div key={i} className="flex items-center gap-2">
                  <Skeleton className="h-4 w-4 rounded-full" />
                  <Skeleton className="h-4 flex-1" />
                </div>
              ))}
            </div>
          </div>

          {/* Steps */}
          <div className="space-y-3">
            <Skeleton className="h-6 w-32" />
            {[1, 2, 3, 4].map((i) => (
              <div key={i} className="flex gap-3">
                <Skeleton className="h-8 w-8 rounded-full flex-shrink-0" />
                <div className="flex-1 space-y-2">
                  <Skeleton className="h-4 w-full" />
                  <Skeleton className="h-4 w-5/6" />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default RecipeDetailSkeleton;
